'use client'
import { useEffect, useRef } from 'react'

const PAL = ['#FFFFFF', '#000000', '#808080', '#0000FF']

// Real Bitfauna on-chain pixel data (tokens 0–3)
const DEMO_DATA: Record<string, string> = {
  '0': '',
  '1': '',
  '2': '',
  '3': '',
}

function hexToPixels(hex: string): Uint8Array {
  const px = new Uint8Array(1600)
  for (let i = 0; i < 1600; i++) {
    const b = parseInt(hex.slice((i >> 2) * 2, (i >> 2) * 2 + 2), 16)
    px[i] = (b >> (6 - (i & 3) * 2)) & 0x3
  }
  return px
}

function renderToCanvas(canvas: HTMLCanvasElement, pixels: Uint8Array) {
  canvas.width = 40; canvas.height = 40
  const ctx = canvas.getContext('2d')!
  for (let i = 0; i < 1600; i++) {
    ctx.fillStyle = PAL[pixels[i]]
    ctx.fillRect(i % 40, i / 40 | 0, 1, 1)
  }
}

export default function Gallery() {
  const refs = [useRef<HTMLCanvasElement>(null), useRef<HTMLCanvasElement>(null), useRef<HTMLCanvasElement>(null), useRef<HTMLCanvasElement>(null)]

  useEffect(() => {
    Object.entries(DEMO_DATA).forEach(([id, hex], i) => {
      if (refs[i]?.current) renderToCanvas(refs[i].current!, hexToPixels(hex))
    })
  }, [])

  return (
    <div className="gallery-row rv">
      {refs.map((ref, i) => (
        <div key={i} className="gallery-cell">
          <canvas ref={ref} width={40} height={40} />
        </div>
      ))}
    </div>
  )
}
